class PageIterator:
    def __init__(self, pages):
        self.pages = pages
        self.page_idx = 0
        self.item_idx = 0

    def __iter__(self):
        return self

    def __next__(self):
        while self.page_idx < len(self.pages):
            page = self.pages[self.page_idx]
            if self.item_idx < len(page):
                item = page[self.item_idx]
                self.item_idx += 1
                return item
            self.page_idx += 1
            self.item_idx = 0
        raise StopIteration

class PaginatedResults:
    def __init__(self, pages):
        self.pages = pages

    def __iter__(self):
        return PageIterator(self.pages)
